/**
 * @param {number[]} nums
 * @param {number} k
 * @return {number}
 */
function solve(nums, k) {
    const N = nums.length;
    const INF = Number.POSITIVE_INFINITY;

    // Maximum possible peaks is floor(N/2)
    if (k > Math.floor(N / 2)) {
        return -1;
    }
    if (k === 0) {
        return 0;
    }

    // Step 1: Calculate costs C_i
    // C_i is the minimum cost to make nums[i] a peak, assuming neighbors are not modified.
    const C = new Array(N);
    for (let i = 0; i < N; i++) {
        const prev = nums[(i - 1 + N) % N];
        const next = nums[(i + 1) % N];
        const required_height = Math.max(prev, next) + 1;
        C[i] = Math.max(0, required_height - nums[i]);
    }

    /**
     * Solves the Minimum Weight Independent Set of size K on a path graph defined by weights W.
     * @param {number[]} W - Weights of vertices (must be non-empty if K > 0)
     * @param {number} targetK - Required number of nodes to select.
     * @returns {number} Minimum cost or INF if impossible.
     */
    const solve_path = (W, targetK) => {
        const L = W.length;
        if (targetK < 0) return INF;
        if (targetK === 0) return 0;
        if (L === 0) return INF;
        if (L < targetK) return INF;

        // DP[i][j][s]: Min cost using W[0..i], selecting j nodes.
        // s=0: W[i] not selected.
        // s=1: W[i] selected.
        // Max j is targetK. Size: L x (targetK+1) x 2

        // We only need DP state for current i and previous i-1
        let dp_prev = Array(targetK + 1).fill(0).map(() => [INF, INF]);
        let dp_curr = Array(targetK + 1).fill(0).map(() => [INF, INF]);

        // Base case i=0
        dp_prev[0][0] = 0; // W[0] not selected, 0 items, cost 0
        dp_prev[1][1] = W[0]; // W[0] selected, 1 item, cost W[0]

        for (let i = 1; i < L; i++) {
            // Reset current DP row
            dp_curr.forEach(row => row[0] = INF);
            dp_curr.forEach(row => row[1] = INF);

            for (let j = 0; j <= targetK; j++) {
                // Case s=0: W[i] not selected
                // Transition from (i-1) selected or not selected
                dp_curr[j][0] = Math.min(dp_prev[j][0], dp_prev[j][1]);

                // Case s=1: W[i] selected
                if (j >= 1) {
                    // Must transition from (i-1) not selected
                    const cost = dp_prev[j - 1][0] + W[i];
                    dp_curr[j][1] = cost;
                }
            }
            // Move current to previous for next iteration
            [dp_prev, dp_curr] = [dp_curr, dp_prev];
        }

        // The result is stored in dp_prev after L-1 iterations
        const result = Math.min(dp_prev[targetK][0], dp_prev[targetK][1]);
        return result;
    };

    // --- Cycle Handling ---

    let min_total_cost = INF;

    // Case 1: Index 0 is NOT selected (S_0_out)
    // Solve MWIS on Path [1, ..., N-1] for exactly k peaks.
    if (N >= 2) {
        const weights_out = C.slice(1);
        const cost1 = solve_path(weights_out, k);
        min_total_cost = Math.min(min_total_cost, cost1);
    }


    // Case 2: Index 0 IS selected (S_0_in)
    // Requires k-1 more peaks from Path [2, ..., N-2].
    if (k >= 1) {
        let cost2_path = 0;
        let L_path = 0;
        let weights_in = [];

        if (N <= 2) {
             // N=2, only C[0] and C[1]. If C[0] chosen, k must be 1. Path is empty.
             if (N === 2 && k === 1) {
                 cost2_path = 0;
                 L_path = 0;
             } else {
                 // Should not happen based on prior checks, but safety
                 cost2_path = INF;
             }
        } else if (N === 3) {
            // N=3, C[0] chosen. Path is empty [2..1].
            cost2_path = 0;
            L_path = 0;
        } else { // N >= 4
            // Path is [2, ..., N-2]. Length N-3.
            weights_in = C.slice(2, N - 1);
            L_path = N - 3;
            const path_cost = solve_path(weights_in, k - 1);
            cost2_path = path_cost;
        }

        if (cost2_path !== INF) {
            const total_cost2 = C[0] + cost2_path;
            min_total_cost = Math.min(min_total_cost, total_cost2);
        }
    }


    return min_total_cost === INF ? -1 : min_total_cost;
}

